def adjudicate(scores: list[float], method: str = "mean") -> float:
    """Resolve annotator disagreement."""
    if method == "mean":
        return sum(scores) / len(scores)
    elif method == "median":
        scores_sorted = sorted(scores)
        n = len(scores_sorted)
        if n % 2 == 1:
            return scores_sorted[n // 2]
        return (scores_sorted[n // 2 - 1] + scores_sorted[n // 2]) / 2.0
    elif method == "majority":
        from collections import Counter
        return Counter(scores).most_common(1)[0][0]
    raise ValueError(f"Unknown method: {method}")

# Flag cases needing adjudication
def flag_disagreements(scores_a, scores_b, threshold=1):
    """Return indices where annotators disagree by more than threshold."""
    return [i for i, (a, b) in enumerate(zip(scores_a, scores_b))
            if abs(a - b) > threshold]
